/**
 * The starter's files, as pure functions of the project name.
 *
 * Each function returns one file's contents as a string. They are
 * deliberately pure and side-effect free: `scaffold` owns all I/O, these
 * own all content, so the generated bytes are tested directly without
 * touching a disk.
 *
 * The app they emit is small but REAL — it boots on `@keel/kernel`'s
 * `createApp` with a `posts` table (defined as a `@keel/db` value), a
 * migration that runs `createTableSql(posts)`, and a code-first `keel()`
 * app whose handlers query via `@keel/db`. Mirrors the shape of the
 * canonical blog example (`examples/blog`) and the rest of the
 * post-ADR-0004 codebase.
 */

/**
 * The `@keel/*` packages a scaffolded app depends on, by directory name under
 * `packages/`.
 *
 * `@keel/cli` is the `keel` binary `keel dev`/`build` runs (its absence was a
 * silent break — blocker #9); `@keel/assets` is the client-bundle pipeline the
 * island build needs in the app's graph. The rest are the app's own runtime
 * (db/kernel/migrate/runtime, the web router, the UI engine).
 */
export const KEEL_PACKAGES = [
  "@keel/cli",
  "@keel/assets",
  "@keel/db",
  "@keel/kernel",
  "@keel/migrate",
  "@keel/runtime",
  "@keel/ui",
  "@keel/web",
] as const;

/**
 * Resolve a `@keel/*` package name to the dependency specifier the scaffold pins
 * it at.
 *
 * Two implementations live in `scaffold.ts`: `publishedRangePin` (the default — a
 * published `^0.x` range an outsider installs from the registry) and
 * `fileColonPin` (a `file:` path at the in-repo package, selected by
 * `create-keel --local` for in-monorepo dev before anything is published). The
 * resolver is injected so a test can pin to a fake specifier and the publish
 * decision lives in exactly one place.
 */
export type KeelDepResolver = (pkg: (typeof KEEL_PACKAGES)[number]) => string;

/**
 * `package.json` for the scaffolded app: starter deps + a `keel dev` script.
 *
 * The `@keel/*` specifiers come from the injected `keelDep` resolver (a `file:`
 * pin today; a published range post-launch), keeping this a pure function of its
 * inputs. The app ships `preact` (the ~10 KB island client the Preact dialect
 * aliases `react` to) AND `react`/`react-dom` (the server still renders React —
 * see `keel.app.ts`'s `ui: { dialect: "preact" }`).
 */
export function packageJson(name: string, keelDep: KeelDepResolver): string {
  const keelDeps = Object.fromEntries(KEEL_PACKAGES.map((pkg) => [pkg, keelDep(pkg)]));

  const manifest = {
    name,
    version: "0.0.0",
    type: "module",
    private: true,
    // A scaffolded app is the user's own private project, not a Keel package — so
    // it declares `UNLICENSED` rather than inheriting Keel's MIT. The author
    // changes this to whatever license their project ships under.
    license: "UNLICENSED",

    scripts: {
      dev: "keel dev",
      build: "keel build",
    },

    dependencies: {
      ...keelDeps,
      "better-sqlite3": "^11.10.0",
      // The Preact dialect (`ui.dialect: "preact"`) aliases the island client's
      // `react` to `preact/compat`, so the app needs `preact` for the ~10 KB
      // client bundle; `react`/`react-dom` back the React server render.
      preact: "^10.29.2",
      react: "^19",
      "react-dom": "^19",
      zod: "^4.0.0",
    },
  };

  return `${JSON.stringify(manifest, null, 2)}\n`;
}

/**
 * `keel.app.ts` — the project root's entrypoint.
 *
 * It default-exports a `KeelAppConfig` (the `{ db, app, migrations }` object
 * `createApp` accepts), which `@keel/cli`'s `keel dev` loads and boots.
 */
export function keelApp(): string {
  return `/**
 * The app: a \`posts\` table, its migration, and a code-first \`keel()\` app,
 * wired into the KeelAppConfig that \`keel dev\` boots. This is the whole
 * application — grow it by adding tables, migrations, routes, and pages.
 *
 * Routes read top-to-bottom like Hono/Express: one \`keel()\` surface for both
 * API routes (\`.get\`/\`.post\`/…) and pages (\`.page\`), each handler a
 * \`(c) => response\` over the request context \`c\`.
 *
 * Two conventions worth seeing on day one:
 *   - Validation at the boundary (ADR 0005): the create handler runs the
 *     untrusted body through a Zod schema with \`c.valid\` before it touches the
 *     database. A bad body is a 422, never a crash. The schema is the only place
 *     input is checked; everything past it is typed and trusted.
 *   - Security on by default, declared in one place: the config's \`secure\` field.
 *     Per-client rate-limiting is on from the kernel default, and \`originCheck\`
 *     adds zero-token CSRF — a state-changing request from another origin is
 *     refused (it reads the browser's \`Sec-Fetch-Site\`), with no token plumbing.
 */

import { createElement } from "react";

import { createDb, createTableSql, defineTable, dropTableSql, integer, text } from "@keel/db";
import type { Db } from "@keel/db";

import type { MigrationEntry } from "@keel/migrate";

import { keel } from "@keel/web";
import { openSqlite } from "@keel/runtime";
import type { KeelAppConfig } from "@keel/kernel";

import { z } from "zod";

import Counter from "./app/islands/counter";

// The \`posts\` table — schema as a value backs both the migration's DDL
// and the inferred row type every query returns.
export const posts = defineTable("posts", {
  id: integer("id").primaryKey({ autoIncrement: true }),
  title: text("title").notNull(),
  body: text("body").notNull(),
  createdAt: text("created_at").notNull(),
  updatedAt: text("updated_at").notNull(),
});

// The schema, version-stamped and idempotent — run on boot by the kernel.
const createPosts: MigrationEntry = {
  version: "001_create_posts",
  migration: {
    up: (schema) => {
      schema.execute(createTableSql(posts));
    },

    down: (schema) => {
      schema.execute(dropTableSql(posts));
    },
  },
};

// The input schema for a new post — semantic validation (non-blank, trimmed)
// lives here, not on the table (the table just says \`notNull()\`). This is the
// untrusted-input contract; see ADR 0005.
const NewPost = z.object({
  title: z.string().trim().min(1, "Title is required."),
  body: z.string().trim().min(1, "Body is required."),
});

// The app — built through a factory so its handlers close over the typed
// \`Db\`. No \`this\`, no global database connection, no inheritance for domain
// types. One \`keel()\` surface for the whole app; grow it by chaining more
// \`.get\`/\`.post\`/\`.page\` calls.
function buildApp(db: Db) {
  return (
    keel()
      // Security is declared on the config below (\`secure\`), not wired here — so
      // this surface stays pure routes + pages.
      // The hydration runtime: \`keel build\`/\`dev\` bundle \`app/islands/\` into
      // this \`/client.js\` (the Preact dialect — see \`ui\` below), and every page
      // gets the head module tag that boots it.
      .client("/client.js")
      // The home page renders the Counter island. Its button does nothing until
      // the client bundle hydrates it — a working click is the visible proof the
      // island came alive on the Preact runtime.
      .page("/", {
        component: () =>
          createElement(
            "main",
            null,
            createElement("h1", null, "Welcome to Keel"),
            createElement(Counter, { start: 0 }),
          ),
      })
      .get("/posts", async (c) => {
        const rows = await db.select().from(posts).orderBy(posts.id, "asc").all();

        return c.json({ posts: rows });
      })
      // POST /posts. \`c.valid\` proves the shape (or throws a 422); past it,
      // \`input\` is a typed \`{ title: string; body: string }\` we can trust.
      .post("/posts", async (c) => {
        const input = c.valid(NewPost);

        const now = new Date().toISOString();

        const post = await db
          .insert(posts)
          .values({ title: input.title, body: input.body, createdAt: now, updatedAt: now })
          .returning()
          .get();

        return c.json({ post }, 201);
      })
  );
}

// The driver seam: \`@keel/runtime\`'s \`openSqlite\` boots better-sqlite3 under
// Node and falls back to the built-in \`bun:sqlite\` under Bun — the framework
// owns that, so the app never has to. The same handle backs the kernel (which
// runs migrations) and the typed \`@keel/db\` the handlers query through.
const { db: handle } = await openSqlite("keel.db");
const db = createDb(handle);

const config: KeelAppConfig = {
  db: handle,
  app: buildApp(db),
  migrations: [createPosts],
  // Security, declared in one place (ADR 0016). Per-client rate-limiting is ALREADY
  // on by the kernel default; \`originCheck\` layers zero-token CSRF over it — a
  // cross-site POST/PUT/PATCH/DELETE is refused at the door (it reads the browser's
  // \`Sec-Fetch-Site\`). Add \`cors\` / the signed-token \`csrf\`, retune \`rateLimit\`,
  // or set \`secure: false\` to opt out entirely.
  secure: { originCheck: {} },
  // The headline default (ADR 0011 Increment 3): \`preact\` ships a ~10 KB island
  // client. The single \`ui.dialect\` key drives BOTH the client bundle's
  // \`react\`→\`preact/compat\` alias (read by \`keel dev\`/\`build\`) and — for a
  // bespoke worker — the server renderer. Switch to \`"react"\` to opt out.
  ui: { dialect: "preact" },
};

export default config;
`;
}

/**
 * `app/islands/counter.tsx` — the one island the starter ships (ADR 0011).
 *
 * One `defineIsland` default-export per file is the convention `keel build`/`dev`
 * discover and bundle into `/client.js`. A deferred (`ssr: false`) island: the
 * server paints its fallback, the Preact client mounts the live component fresh —
 * the sound pairing while the CLI server renders React (full server-side Preact is
 * estate's bespoke whole-process-aliased path). The `useState` button is inert
 * until hydration, so a working click is the visible proof the island came alive.
 */
export function islandCounter(): string {
  return `import { useState } from "react";
import type { ReactElement } from "react";

import { defineIsland } from "@keel/ui";

/** A trivial interactive component: the local count proves hydration is live. */
function Counter({ start }: { start: number }): ReactElement {
  const [n, setN] = useState(start);

  return (
    <button type="button" data-testid="counter" onClick={() => setN((value) => value + 1)}>
      count: {n}
    </button>
  );
}

/** Deferred island: server paints the fallback, the client mounts Counter fresh. */
export default defineIsland({
  name: "Counter",
  component: Counter,
  fallback: ({ start }) => <button type="button" data-testid="counter">count: {start}</button>,
});
`;
}

/**
 * `keel.sites.ts` — the project's declared sites, mirroring `keel.app.ts`.
 *
 * `keel build`/`dev` read its default export. A single dynamic site at `/` runs
 * the whole app live; grow it (static zones, multiple origins) as the app does.
 * Its presence is also what keeps `keel build` from crashing — a missing
 * `keel.sites.ts` is tolerated (app-only dispatch), but shipping one is the
 * starting point every real app grows from.
 */
export function keelSites(): string {
  return `import type { Site } from "@keel/sites";

/**
 * One dynamic site at the root: every route runs live through the app's handler.
 * Add static zones (\`render: "static"\` with a \`pages\` list) or extra origins
 * here as the app grows.
 */
const sites: Site[] = [{ name: "app", render: "dynamic", basePath: "/" }];

export default sites;
`;
}

/** `tsconfig.json` for the scaffolded app: strict, ESM, bundler resolution. */
export function tsconfig(): string {
  const config = {
    compilerOptions: {
      target: "ES2023",
      // DOM for the island's browser APIs (`useState` over a real button), ES2023
      // for the server. The client bundle is compiled by `Bun.build`, not tsc.
      lib: ["ES2023", "DOM", "DOM.Iterable"],
      module: "ESNext",
      moduleResolution: "Bundler",
      verbatimModuleSyntax: true,
      isolatedModules: true,
      resolveJsonModule: true,
      strict: true,
      jsx: "react-jsx",
      types: ["node"],
      skipLibCheck: true,
    },
    include: ["keel.app.ts", "keel.sites.ts", "app"],
  };

  return `${JSON.stringify(config, null, 2)}\n`;
}

/** `.gitignore` — keep build artefacts and the local SQLite file out of git. */
export function gitignore(): string {
  return ["node_modules/", "*.db", "*.db-journal", "dist/", "out/", ".DS_Store", ""].join("\n");
}

/** `README.md` — how to run the freshly scaffolded app. */
export function readme(name: string): string {
  return `# ${name}

A Keel app — batteries included.

## Develop

\`\`\`sh
bun install
bun run dev
\`\`\`

\`keel dev\` loads \`keel.app.ts\` (which default-exports the app config) and
boots it: the kernel runs migrations and stands up request dispatch over
the typed \`@keel/db\` handle the route handlers query through.

## Structure

- \`keel.app.ts\` — the whole app: a \`posts\` table (defined via
  \`@keel/db\`'s \`defineTable\`), its migration, and a code-first \`keel()\`
  app built through a closure factory, with \`.get("/posts")\` /
  \`.post("/posts")\` route handlers.
- The \`POST /posts\` handler validates the request body at the boundary with
  a Zod schema via \`c.valid\` — a bad body is a 422, never a crash.
  See \`docs/adr/0005-validation-at-the-boundary.md\` in the Keel source.
- Security is on by default, declared via the config's \`secure\` field: per-client
  rate-limiting comes from the kernel default, and \`secure: { originCheck: {} }\`
  adds zero-token, header-based CSRF — cross-site state-changing requests are
  refused. Note a non-browser client (e.g. \`curl\`) sends no \`Sec-Fetch-Site\`, so
  it is refused too — pass \`Sec-Fetch-Site: same-origin\` when testing by hand.
`;
}
